<?php
declare(strict_types=1);
require __DIR__ . '/../partials/bootstrap.php';
if (($_SESSION['perpus_user_role'] ?? '') !== 'admin') { http_response_code(403); return; }
$notice='';$error='';$currentId=(int)($_SESSION['perpus_user_id']??0);
try {
 if($_SERVER['REQUEST_METHOD']==='POST'){
  perpus_check_csrf();$action=(string)($_POST['action']??'');$id=(int)($_POST['id']??0);
  if($action==='create'){
   $username=strtolower(trim((string)($_POST['username']??'')));$name=trim((string)($_POST['name']??''));$email=trim((string)($_POST['email']??''));$role='staf';$password=(string)($_POST['password']??'');
   if(!preg_match('/^[a-z0-9._-]{3,50}$/',$username))throw new RuntimeException('Username minimal 3 karakter dan hanya boleh berisi huruf kecil, angka, titik, garis bawah, atau strip.');
   if($name===''||mb_strlen($name)>120)throw new RuntimeException('Nama lengkap wajib diisi.');
   if($email!==''&&!filter_var($email,FILTER_VALIDATE_EMAIL))throw new RuntimeException('Format email tidak valid.');
   if(strlen($password)<8)throw new RuntimeException('Password minimal 8 karakter.');
   $hash=password_hash($password,PASSWORD_DEFAULT);$emailValue=$email===''?null:$email;
   $stmt=$conn->prepare("INSERT INTO perpus_users(username,email,password,nama_lengkap,role,status) VALUES(?,?,?,?,?,'aktif')");$stmt->bind_param('sssss',$username,$emailValue,$hash,$name,$role);$stmt->execute();$stmt->close();$notice='Pengguna berhasil ditambahkan.';
  } elseif($action==='toggle'){
   if($id===$currentId)throw new RuntimeException('Anda tidak dapat menonaktifkan akun sendiri.');
   $stmt=$conn->prepare('SELECT role,status,sds_admin_id FROM perpus_users WHERE id=?');$stmt->bind_param('i',$id);$stmt->execute();$target=$stmt->get_result()->fetch_assoc();$stmt->close();if(!$target)throw new RuntimeException('Pengguna tidak ditemukan.');
   if(!empty($target['sds_admin_id']))throw new RuntimeException('Akun admin ini dikelola oleh superadmin melalui SDS.');
   if($target['role']==='admin'&&$target['status']==='aktif'){ $n=(int)($conn->query("SELECT COUNT(*) total FROM perpus_users WHERE role='admin' AND status='aktif'")->fetch_assoc()['total']??0);if($n<=1)throw new RuntimeException('Admin aktif terakhir tidak dapat dinonaktifkan.'); }
   $status=$target['status']==='aktif'?'nonaktif':'aktif';$stmt=$conn->prepare('UPDATE perpus_users SET status=? WHERE id=?');$stmt->bind_param('si',$status,$id);$stmt->execute();$stmt->close();$notice='Status pengguna diperbarui.';
  } elseif($action==='password'){
   $stmt=$conn->prepare('SELECT sds_admin_id FROM perpus_users WHERE id=?');$stmt->bind_param('i',$id);$stmt->execute();$target=$stmt->get_result()->fetch_assoc();$stmt->close();if(!$target)throw new RuntimeException('Pengguna tidak ditemukan.');if(!empty($target['sds_admin_id']))throw new RuntimeException('Password admin dikelola melalui SDS.');
   $password=(string)($_POST['password']??'');if(strlen($password)<8)throw new RuntimeException('Password baru minimal 8 karakter.');$hash=password_hash($password,PASSWORD_DEFAULT);$stmt=$conn->prepare('UPDATE perpus_users SET password=? WHERE id=?');$stmt->bind_param('si',$hash,$id);$stmt->execute();$stmt->close();$notice='Password staf diperbarui.';
  }
 }
}catch(mysqli_sql_exception $e){$error=$e->getCode()===1062?'Username atau email sudah digunakan.':'Gagal menyimpan pengguna.';}catch(Throwable $e){$error=$e->getMessage();}
$users=[];$q=$conn->query('SELECT id,sds_admin_id,username,email,nama_lengkap,role,status,last_login_at,created_at FROM perpus_users ORDER BY status DESC,role, nama_lengkap');while($q&&($row=$q->fetch_assoc()))$users[]=$row;
?>
<?php if($notice):?><div class="alert alert-success"><?=perpus_h($notice)?></div><?php endif;?><?php if($error):?><div class="alert alert-danger"><?=perpus_h($error)?></div><?php endif;?>
<div class="row"><div class="col-lg-4"><div class="card"><div class="card-header"><h5 class="card-title mb-0">Tambah Staf Perpustakaan</h5></div><div class="card-body"><div class="alert alert-info small">Admin Perpustakaan dibuat oleh superadmin melalui SDS. Di sini Anda hanya mengelola staf.</div><form method="post"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><input type="hidden" name="action" value="create"><div class="mb-3"><label class="form-label">Nama lengkap</label><input class="form-control" name="name" required maxlength="120"></div><div class="mb-3"><label class="form-label">Username</label><input class="form-control" name="username" required minlength="3" maxlength="50"></div><div class="mb-3"><label class="form-label">Email (opsional)</label><input class="form-control" type="email" name="email"></div><div class="mb-3"><label class="form-label">Password awal</label><input class="form-control" type="password" name="password" required minlength="8" autocomplete="new-password"></div><button class="btn btn-primary w-100">Tambah Staf</button></form></div></div></div><div class="col-lg-8"><div class="card"><div class="card-header"><h5 class="card-title mb-0">Admin & Staf Perpustakaan</h5></div><div class="table-responsive"><table class="table table-hover mb-0"><thead><tr><th>Pengguna</th><th>Peran</th><th>Status</th><th>Login terakhir</th><th>Aksi</th></tr></thead><tbody><?php foreach($users as $u):?><tr><td><strong><?=perpus_h($u['nama_lengkap'])?></strong><div class="small text-muted">@<?=perpus_h($u['username'])?><?=!empty($u['email'])?' · '.perpus_h($u['email']):''?></div></td><td><span class="badge bg-<?=$u['role']==='admin'?'primary':'secondary'?>"><?=perpus_h(ucfirst($u['role']))?></span></td><td><span class="badge bg-<?=$u['status']==='aktif'?'success':'light text-dark'?>"><?=perpus_h(ucfirst($u['status']))?></span></td><td class="small"><?=perpus_h($u['last_login_at']?:'Belum pernah')?></td><td><form method="post" class="d-inline"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><input type="hidden" name="action" value="toggle"><input type="hidden" name="id" value="<?=(int)$u['id']?>"><button class="btn btn-sm btn-outline-secondary" <?=$u['id']===$currentId?'disabled':''?>><?=$u['status']==='aktif'?'Nonaktifkan':'Aktifkan'?></button></form><form method="post" class="d-flex gap-1 mt-2"><input type="hidden" name="csrf" value="<?=perpus_h(perpus_csrf())?>"><input type="hidden" name="action" value="password"><input type="hidden" name="id" value="<?=(int)$u['id']?>"><input class="form-control form-control-sm" type="password" name="password" minlength="8" required placeholder="Password baru"><button class="btn btn-sm btn-outline-primary">Reset</button></form></td></tr><?php endforeach;?></tbody></table></div></div></div></div>
